<script setup lang="ts">
/**
 * 角色页:与主页弹窗共用同一个 RolePanel 组件,只去掉 Modal 外壳
 * 进 /role 直接看到人物属性面板
 * 关闭按钮(@close)→ router.back() 回到 /huzhong
 */
import { useRouter } from 'vue-router'
import GameLayout from '@/layouts/GameLayout.vue'
import RolePanel from '@/components/role/RolePanel.vue'

const router = useRouter()
function goBack() {
  if (window.history.length > 1) router.back()
  else router.push('/huzhong')
}
</script>

<template>
  <GameLayout>
    <div class="absolute left-1/2 -translate-x-1/2 top-[68px] z-10">
      <RolePanel @close="goBack" />
    </div>
  </GameLayout>
</template>
